import { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { enrollmentsService } from '../../services/enrollments';
import './Dashboard.css';

const StudentDashboard = () => {
  const [enrollments, setEnrollments] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    loadEnrollments();
  }, []);

  const loadEnrollments = async () => {
    try {
      setLoading(true);
      const data = await enrollmentsService.getMyCourses();
      setEnrollments(data);
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  if (loading) {
    return <div className="loading">Loading your courses...</div>;
  }

  return (
    <div className="dashboard">
      <h1>My Courses</h1>
      {enrollments.length === 0 ? (
        <div className="empty-state">
          <p>You haven't enrolled in any courses yet.</p>
          <Link to="/courses" className="btn btn-primary">
            Browse Courses
          </Link>
        </div>
      ) : (
        <div className="enrollments-grid">
          {enrollments.map((enrollment) => (
            <div key={enrollment.id} className="enrollment-card">
              <Link to={`/courses/${enrollment.course.id}`}>
                {enrollment.course.image_url ? (
                  <img
                    src={enrollment.course.image_url}
                    alt={enrollment.course.title}
                  />
                ) : (
                  <div className="course-image-placeholder">No Image</div>
                )}
                <div className="enrollment-info">
                  <h3>{enrollment.course.title}</h3>
                  <p>Enrolled: {new Date(enrollment.enrolled_at).toLocaleDateString()}</p>
                  <Link
                    to={`/courses/${enrollment.course.id}`}
                    className="btn btn-success"
                    onClick={(e) => e.stopPropagation()}
                  >
                    Continue Learning
                  </Link>
                </div>
              </Link>
            </div>
          ))}
        </div>
      )}
    </div>
  );
};

export default StudentDashboard;
